                                                                                                                                                                                                                                                                                    elseif
                                                                                                                                                                                                                                                                                        l_str2 = = "military" then
                                                                                                                                                                                                                                                                                        t_gate[i].
                                                                                                                                                                                                                                                                                        Military = "1"
                                                                                                                                                                                                                                                                                        t_gate[i].
                                                                                                                                                                                                                                                                                        Types = "0 " .. t_gate[i].Types
                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                end
