                                                                                                                                                                                                                                                                                    f_value = nil
                                                                                                                                                                                                                                                                                    t_taxinode[i].
                                                                                                                                                                                                                                                                                    g_value = nil
                                                                                                                                                                                                                                                                                    t_taxinode[i].
