                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                function decipher_taxisegment(in_str)
                                                                                                                                                                                                                                                                                    local l_str1, l_str2, l_str3, l_str4, l_str5 = "", "", "", "", ""
                                                                                                                                                                                                                                                                                    local l_idx = 0
                                                                                                                                                                                                                                                                                    i = #t_segment + 1
                                                                                                                                                                                                                                                                                    t_segment[i] = {}
                                                                                                                                                                                                                                                                                    l_str1, l_str2, l_str3, l_str4, l_str5 = string.match(in_str, "1202 %s*([^%s]+)%s*([^%s]+)%s*([^%s]+)%s*([^%s]+)%s*([^%s]+)%s*")
                                                                                                                                                                                                                                                                                    t_segment[i].
                                                                                                                                                                                                                                                                                    Node1 = tonumber(l_str1)
                                                                                                                                                                                                                                                                                    t_segment[i].
                                                                                                                                                                                                                                                                                    Node2 = tonumber(l_str2)
                                                                                                                                                                                                                                                                                    t_segment[i].
                                                                                                                                                                                                                                                                                    Dir = l_str3
                                                                                                                                                                                                                                                                                    if string.find(l_str4, "runway") then
                                                                                                                                                                                                                                                                                        t_segment[i].
                                                                                                                                                                                                                                                                                        Type = "runway"
                                                                                                                                                                                                                                                                                        t_taxinode[t_segment[i].Node1 + 1].
                                                                                                                                                                                                                                                                                        Type = "runway"
                                                                                                                                                                                                                                                                                        t_taxinode[t_segment[i].Node2 + 1].
                                                                                                                                                                                                                                                                                        Type = "runway"
                                                                                                                                                                                                                                                                                        l_idx = #t_runway_node + 1
                                                                                                                                                                                                                                                                                        t_runway_node[l_idx] = t_segment[i].Node1
                                                                                                                                                                                                                                                                                        t_runway_node[l_idx + 1] = t_segment[i].Node2
                                                                                                                                                                                                                                                                                        else
                                                                                                                                                                                                                                                                                            if string.sub(l_str4, string.len(l_str4) - 1, -2) == "_" then
                                                                                                                                                                                                                                                                                                t_segment[i].
                                                                                                                                                                                                                                                                                                Size = string.sub(l_str4, string.len(l_str4), -1)
                                                                                                                                                                                                                                                                                                else
                                                                                                                                                                                                                                                                                                    t_segment[i].
                                                                                                                                                                                                                                                                                                    Size = ""
                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                t_segment[i].
                                                                                                                                                                                                                                                                                                Type = "taxiway"
                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                            t_segment[i].
                                                                                                                                                                                                                                                                                            ID = l_str5
                                                                                                                                                                                                                                                                                            t_segment[i].
                                                                                                                                                                                                                                                                                            Hotzone = ""
                                                                                                                                                                                                                                                                                            t_segment[i].Heading, t_segment[i].
                                                                                                                                                                                                                                                                                            Dist = heading_n_dist(
                                                                                                                                                                                                                                                                                            t_taxinode[t_segment[i].Node1 + 1].x, t_taxinode[t_segment[i].Node1 + 1].z, t_taxinode[t_segment[i].Node2 + 1].x, t_taxinode[t_segment[i].Node2 + 1].z
                                                                                                                                                                                                                                                                                            )
                                                                                                                                                                                                                                                                                            if t_taxinode[t_segment[i].Node1 + 1].
                                                                                                                                                                                                                                                                                                Segment = = "" then
                                                                                                                                                                                                                                                                                                t_taxinode[t_segment[i].Node1 + 1].
                                                                                                                                                                                                                                                                                                Segment = tostring(i)
                                                                                                                                                                                                                                                                                                else
                                                                                                                                                                                                                                                                                                    t_taxinode[t_segment[i].Node1 + 1].
                                                                                                                                                                                                                                                                                                    Segment = t_taxinode[t_segment[i].Node1 + 1].Segment .. ", " .. tostring(i)
                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                if t_taxinode[t_segment[i].Node2 + 1].
                                                                                                                                                                                                                                                                                                    Segment = = "" then
                                                                                                                                                                                                                                                                                                    t_taxinode[t_segment[i].Node2 + 1].
                                                                                                                                                                                                                                                                                                    Segment = tostring(i)
                                                                                                                                                                                                                                                                                                    else
                                                                                                                                                                                                                                                                                                        t_taxinode[t_segment[i].Node2 + 1].
                                                                                                                                                                                                                                                                                                        Segment = t_taxinode[t_segment[i].Node2 + 1].Segment .. ", " .. tostring(i)
                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                function decipher_taxisegment_hotzone(in_str)
                                                                                                                                                                                                                                                                                                    i = #t_segment
                                                                                                                                                                                                                                                                                                    t_segment[i].
                                                                                                                                                                                                                                                                                                    Hotzone = string.match(in_str, "1204 %s*[^%s]+%s*([^%s]+)%s*")
                                                                                                                                                                                                                                                                                                    if t_segment[i].
                                                                                                                                                                                                                                                                                                        Type = = "taxiway" then
                                                                                                                                                                                                                                                                                                        if t_taxinode[t_segment[i].Node1 + 1].Type ~= "runway" then
                                                                                                                                                                                                                                                                                                            t_taxinode[t_segment[i].Node1 + 1].
                                                                                                                                                                                                                                                                                                            Type = "hotzone"
                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                        if t_taxinode[t_segment[i].Node2 + 1].Type ~= "runway" then
                                                                                                                                                                                                                                                                                                            t_taxinode[t_segment[i].Node2 + 1].
                                                                                                                                                                                                                                                                                                            Type = "hotzone"
                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                function decipher_vehicle_edge(in_str)
                                                                                                                                                                                                                                                                                                    local l_str1, l_str2 = string.match(in_str, "1206 %s*([^%s]+)%s*([^%s]+)%s*")
                                                                                                                                                                                                                                                                                                    if l_str1 and l_str2 then
                                                                                                                                                                                                                                                                                                        local l_n1 = tonumber(l_str1)
                                                                                                                                                                                                                                                                                                        local l_n2 = tonumber(l_str2)
                                                                                                                                                                                                                                                                                                        if l_n1 ~= nil and l_n2 ~= nil then
                                                                                                                                                                                                                                                                                                            local l_idx = #t_filter_1206 + 1
                                                                                                                                                                                                                                                                                                            t_filter_1206[l_idx] = {
                                                                                                                                                                                                                                                                                                            Node1 = l_n1, Node2 = l_n2 }
                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                function apply_1206_filter()
                                                                                                                                                                                                                                                                                                    if #
                                                                                                                                                                                                                                                                                                        t_filter_1206 = = 0 then
                                                                                                                                                                                                                                                                                                        return
                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                    local l_used = {}
                                                                                                                                                                                                                                                                                                    for
                                                                                                                                                                                                                                                                                                        l_s = 1, #t_segment do
                                                                                                                                                                                                                                                                                                        l_used[t_segment[l_s].Node1] = true
                                                                                                                                                                                                                                                                                                        l_used[t_segment[l_s].Node2] = true
                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                    local l_remove = {}
                                                                                                                                                                                                                                                                                                    for
                                                                                                                                                                                                                                                                                                        l_f = 1, #t_filter_1206 do
                                                                                                                                                                                                                                                                                                        local l_n1 = t_filter_1206[l_f].Node1
                                                                                                                                                                                                                                                                                                        local l_n2 = t_filter_1206[l_f].Node2
                                                                                                                                                                                                                                                                                                        if not l_used[l_n1] then
                                                                                                                                                                                                                                                                                                            l_remove[l_n1] = true
                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                        if not l_used[l_n2] then
                                                                                                                                                                                                                                                                                                            l_remove[l_n2] = true
                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                    local l_count = 0
                                                                                                                                                                                                                                                                                                    for l_id, _ in pairs(l_remove) do
                                                                                                                                                                                                                                                                                                        if t_taxinode[l_id + 1] ~= nil then
                                                                                                                                                                                                                                                                                                            l_count = l_count + 1
                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                    local l_seg_count = 0
                                                                                                                                                                                                                                                                                                    local l_new_segments = {}
                                                                                                                                                                                                                                                                                                    for
                                                                                                                                                                                                                                                                                                        l_s = 1, #t_segment do
                                                                                                                                                                                                                                                                                                        if l_remove[t_segment[l_s].Node1] or l_remove[t_segment[l_s].Node2] then
                                                                                                                                                                                                                                                                                                            l_seg_count = l_seg_count + 1
                                                                                                                                                                                                                                                                                                            else
                                                                                                                                                                                                                                                                                                                l_new_segments[#l_new_segments + 1] = t_segment[l_s]
                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                        for
                                                                                                                                                                                                                                                                                                            l_s = 1, #l_new_segments do
                                                                                                                                                                                                                                                                                                            t_segment[l_s] = l_new_segments[l_s]
                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                        for
                                                                                                                                                                                                                                                                                                            l_s = #l_new_segments + 1, #t_segment + l_seg_count do
                                                                                                                                                                                                                                                                                                            t_segment[l_s] = nil
                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                        for
                                                                                                                                                                                                                                                                                                            l_idx = 1, #t_taxinode do
                                                                                                                                                                                                                                                                                                            if t_taxinode[l_idx] ~= nil then
                                                                                                                                                                                                                                                                                                                t_taxinode[l_idx].
                                                                                                                                                                                                                                                                                                                Segment = ""
                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                        for
                                                                                                                                                                                                                                                                                                            l_s = 1, #t_segment do
                                                                                                                                                                                                                                                                                                            local l_n1idx = t_segment[l_s].Node1 + 1
                                                                                                                                                                                                                                                                                                            local l_n2idx = t_segment[l_s].Node2 + 1
                                                                                                                                                                                                                                                                                                            if t_taxinode[l_n1idx] ~= nil then
                                                                                                                                                                                                                                                                                                                if t_taxinode[l_n1idx].
                                                                                                                                                                                                                                                                                                                    Segment = = "" then
                                                                                                                                                                                                                                                                                                                    t_taxinode[l_n1idx].
                                                                                                                                                                                                                                                                                                                    Segment = tostring(l_s)
                                                                                                                                                                                                                                                                                                                    else
                                                                                                                                                                                                                                                                                                                        t_taxinode[l_n1idx].
                                                                                                                                                                                                                                                                                                                        Segment = t_taxinode[l_n1idx].Segment .. ", " .. tostring(l_s)
                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                if t_taxinode[l_n2idx] ~= nil then
                                                                                                                                                                                                                                                                                                                    if t_taxinode[l_n2idx].
                                                                                                                                                                                                                                                                                                                        Segment = = "" then
                                                                                                                                                                                                                                                                                                                        t_taxinode[l_n2idx].
                                                                                                                                                                                                                                                                                                                        Segment = tostring(l_s)
                                                                                                                                                                                                                                                                                                                        else
                                                                                                                                                                                                                                                                                                                            t_taxinode[l_n2idx].
                                                                                                                                                                                                                                                                                                                            Segment = t_taxinode[l_n2idx].Segment .. ", " .. tostring(l_s)
                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                logMsg(
                                                                                                                                                                                                                                                                                                                "FollowMe VER1.23 : apply_1206_filter() removed "
                                                                                                                                                                                                                                                                                                                .. l_count
                                                                                                                                                                                                                                                                                                                .. " vehicle-only nodes and "
                                                                                                                                                                                                                                                                                                                .. l_seg_count
                                                                                                                                                                                                                                                                                                                .. " orphaned segments at "
                                                                                                                                                                                                                                                                                                                .. (curr_ICAO ~= "" and curr_ICAO or "unknown")
                                                                                                                                                                                                                                                                                                                )
                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                            function determine_runway_node()
                                                                                                                                                                                                                                                                                                                local l_idx = 0
                                                                                                                                                                                                                                                                                                                for
                                                                                                                                                                                                                                                                                                                    l_idx = 1, #t_runway do
                                                                                                                                                                                                                                                                                                                    match_runway(l_idx)
                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                local l_rows = #t_runway
                                                                                                                                                                                                                                                                                                                l_idx = 1
                                                                                                                                                                                                                                                                                                                while l_idx <= l_rows do
                                                                                                                                                                                                                                                                                                                    if t_runway[l_idx].
                                                                                                                                                                                                                                                                                                                        Node = = -1 then
                                                                                                                                                                                                                                                                                                                        t_deleted_runway[#t_deleted_runway + 1] = t_runway[l_idx].ID
                                                                                                                                                                                                                                                                                                                        table.remove(t_runway, l_idx)
                                                                                                                                                                                                                                                                                                                        l_rows = l_rows - 1
                                                                                                                                                                                                                                                                                                                        else
                                                                                                                                                                                                                                                                                                                            l_idx = l_idx + 1
                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                function match_runway(in_runway_idx)
                                                                                                                                                                                                                                                                                                                    local l_idx = 0
                                                                                                                                                                                                                                                                                                                    local l_curr_dist = 0
                                                                                                                                                                                                                                                                                                                    local l_min_dist_twy = 99999
                                                                                                                                                                                                                                                                                                                    local l_min_dist_any = 99999
                                                                                                                                                                                                                                                                                                                    local l_best_twy = -1
                                                                                                                                                                                                                                                                                                                    local l_best_any = -1
                                                                                                                                                                                                                                                                                                                    local l_rwy_x = t_runway[in_runway_idx].x
                                                                                                                                                                                                                                                                                                                    local l_rwy_z = t_runway[in_runway_idx].z
                                                                                                                                                                                                                                                                                                                    local l_rwy_id = t_runway[in_runway_idx].ID
                                                                                                                                                                                                                                                                                                                    local l_rwy_nodes = {}
                                                                                                                                                                                                                                                                                                                    for
                                                                                                                                                                                                                                                                                                                        l_seg = 1, #t_segment do
                                                                                                                                                                                                                                                                                                                        if t_segment[l_seg].
                                                                                                                                                                                                                                                                                                                            Type = = "runway" then
                                                                                                                                                                                                                                                                                                                            local l_seg_id = t_segment[l_seg].ID or ""
                                                                                                                                                                                                                                                                                                                            local l_match = false
                                                                                                                                                                                                                                                                                                                            for l_part in (l_seg_id .. "/"):gmatch("([^/]+)/") do
                                                                                                                                                                                                                                                                                                                                if
                                                                                                                                                                                                                                                                                                                                    l_part = = l_rwy_id then
                                                                                                                                                                                                                                                                                                                                    l_match = true
                                                                                                                                                                                                                                                                                                                                    break
                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                            if l_match then
                                                                                                                                                                                                                                                                                                                                l_rwy_nodes[t_segment[l_seg].Node1] = true
                                                                                                                                                                                                                                                                                                                                l_rwy_nodes[t_segment[l_seg].Node2] = true
                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                    local l_has_own_segs = false
                                                                                                                                                                                                                                                                                                                    for _ in pairs(l_rwy_nodes) do
                                                                                                                                                                                                                                                                                                                        l_has_own_segs = true
                                                                                                                                                                                                                                                                                                                        break
                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                    for
                                                                                                                                                                                                                                                                                                                        l_idx = 1, #t_taxinode do
                                                                                                                                                                                                                                                                                                                        if t_taxinode[l_idx].
                                                                                                                                                                                                                                                                                                                            Type = = "runway" then
                                                                                                                                                                                                                                                                                                                            local l_node_id = l_idx - 1
                                                                                                                                                                                                                                                                                                                            if l_has_own_segs and not l_rwy_nodes[l_node_id] then
                                                                                                                                                                                                                                                                                                                                else
                                                                                                                                                                                                                                                                                                                                    _, l_curr_dist = heading_n_dist(t_taxinode[l_idx].x, t_taxinode[l_idx].z, l_rwy_x, l_rwy_z)
                                                                                                                                                                                                                                                                                                                                    if l_curr_dist < l_min_dist_any then
                                                                                                                                                                                                                                                                                                                                        l_min_dist_any = l_curr_dist
                                                                                                                                                                                                                                                                                                                                        l_best_any = l_node_id
                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                    local l_has_twy = false
                                                                                                                                                                                                                                                                                                                                    for
                                                                                                                                                                                                                                                                                                                                        l_seg = 1, #t_segment do
                                                                                                                                                                                                                                                                                                                                        if
                                                                                                                                                                                                                                                                                                                                            (t_segment[l_seg].
                                                                                                                                                                                                                                                                                                                                            Node1 = = l_node_id or t_segment[l_seg].Node2 == l_node_id)
                                                                                                                                                                                                                                                                                                                                            and t_segment[l_seg].Type ~= "runway"
                                                                                                                                                                                                                                                                                                                                            then
                                                                                                                                                                                                                                                                                                                                            l_has_twy = true
                                                                                                                                                                                                                                                                                                                                            break
                                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                    if l_has_twy and l_curr_dist < l_min_dist_twy then
                                                                                                                                                                                                                                                                                                                                        l_min_dist_twy = l_curr_dist
                                                                                                                                                                                                                                                                                                                                        l_best_twy = l_node_id
                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                        local l_chosen = l_best_twy
                                                                                                                                                                                                                                                                                                                        local l_chosen_dist = l_min_dist_twy
                                                                                                                                                                                                                                                                                                                        if
                                                                                                                                                                                                                                                                                                                            l_chosen = = -1 then
                                                                                                                                                                                                                                                                                                                            l_chosen = l_best_any
                                                                                                                                                                                                                                                                                                                            l_chosen_dist = l_min_dist_any
                                                                                                                                                                                                                                                                                                                            logMsg(
                                                                                                                                                                                                                                                                                                                            "FollowMe VER1.15 : RWY "
                                                                                                                                                                                                                                                                                                                            .. l_rwy_id
                                                                                                                                                                                                                                                                                                                            .. " - no taxiway-connected node found, using closest node "
                                                                                                                                                                                                                                                                                                                            .. l_chosen
                                                                                                                                                                                                                                                                                                                            .. " ("
                                                                                                                                                                                                                                                                                                                            .. string.format("%.1f", l_chosen_dist)
                                                                                                                                                                                                                                                                                                                            .. "m)"
                                                                                                                                                                                                                                                                                                                            )
                                                                                                                                                                                                                                                                                                                            else
                                                                                                                                                                                                                                                                                                                                logMsg(
                                                                                                                                                                                                                                                                                                                                "FollowMe VER1.15 : RWY "
                                                                                                                                                                                                                                                                                                                                .. l_rwy_id
                                                                                                                                                                                                                                                                                                                                .. " -> node "
                                                                                                                                                                                                                                                                                                                                .. l_chosen
                                                                                                                                                                                                                                                                                                                                .. " ("
                                                                                                                                                                                                                                                                                                                                .. string.format("%.1f", l_chosen_dist)
                                                                                                                                                                                                                                                                                                                                .. "m from threshold)"
                                                                                                                                                                                                                                                                                                                                )
                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                            if l_chosen >= 0 then
                                                                                                                                                                                                                                                                                                                                t_runway[in_runway_idx].
                                                                                                                                                                                                                                                                                                                                Node = l_chosen
                                                                                                                                                                                                                                                                                                                                t_taxinode[l_chosen + 1].
                                                                                                                                                                                                                                                                                                                                Runway = l_rwy_id
                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                        function full_reset()
                                                                                                                                                                                                                                                                                                                            if FM_car_active then
                                                                                                                                                                                                                                                                                                                                unload_object()
                                                                                                                                                                                                                                                                                                                                unload_path()
                                                                                                                                                                                                                                                                                                                                unload_rampstart()
                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                            FM_car_active = false
                                                                                                                                                                                                                                                                                                                            prepare_kill_objects = false
                                                                                                                                                                                                                                                                                                                            prepare_show_objects = false
                                                                                                                                                                                                                                                                                                                            kill_is_manual = false
                                                                                                                                                                                                                                                                                                                            ground_time = 0
                                                                                                                                                                                                                                                                                                                            flightstart = 0
                                                                                                                                                                                                                                                                                                                            t_deleted_runway = {}
                                                                                                                                                                                                                                                                                                                            curr_ICAO = ""
                                                                                                                                                                                                                                                                                                                            initialise_airport()
                                                                                                                                                                                                                                                                                                                            initialise_routes()
                                                                                                                                                                                                                                                                                                                            logMsg("FollowMe VER1.12 : full_reset() completed")
                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                        function initialise_airport()
                                                                                                                                                                                                                                                                                                                            t_runway, t_runway_node, t_gate, t_taxinode, t_segment = {}, {}, {}, {}, {}
                                                                                                                                                                                                                                                                                                                            t_filter_1206 = {}
                                                                                                                                                                                                                                                                                                                            depart_arrive = 0
                                                                                                                                                                                                                                                                                                                            depart_gate, arrival_gate, depart_runway, gatetext = 0, 0, "", ""
                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                        function initialise_routes()
                                                                                                                                                                                                                                                                                                                            if #t_node > 0 then
                                                                                                                                                                                                                                                                                                                                if
                                                                                                                                                                                                                                                                                                                                    depart_arrive = = 1 and curr_node >= #t_node and flightstart ~= 9999 and not kill_is_manual then
                                                                                                                                                                                                                                                                                                                                    logMsg("FollowMe VER1.20 : initialise_routes() play_sound(snd_safeflight_bye)")
                                                                                                                                                                                                                                                                                                                                    play_sound(snd_safeflight_bye)
                                                                                                                                                                                                                                                                                                                                    elseif
                                                                                                                                                                                                                                                                                                                                        depart_arrive = = 2 and curr_node == #t_node then
                                                                                                                                                                                                                                                                                                                                        logMsg("FollowMe VER1.20 : initialise_routes() play_sound(snd_welcome_bye)")
                                                                                                                                                                                                                                                                                                                                        play_sound(snd_welcome_bye)
                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                t_node = {}
                                                                                                                                                                                                                                                                                                                                Err_Msg[1] = {}
                                                                                                                                                                                                                                                                                                                                Err_Msg[2] = {}
                                                                                                                                                                                                                                                                                                                                Err_Msg[3] = {}
                                                                                                                                                                                                                                                                                                                                depart_arrive = 0
                                                                                                                                                                                                                                                                                                                                is_backtaxi = false
                                                                                                                                                                                                                                                                                                                                window_first_access = true
                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                            function handle_plugin_window()
                                                                                                                                                                                                                                                                                                                                if fm_new_flight < prev_new_flight and prev_new_flight > 5 then
                                                                                                                                                                                                                                                                                                                                    full_reset()
                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                prev_new_flight = fm_new_flight
                                                                                                                                                                                                                                                                                                                                if prev_plane_x ~= 0 then
                                                                                                                                                                                                                                                                                                                                    local _, l_teleport_dist = heading_n_dist(prev_plane_x, prev_plane_z, fm_plane_x, fm_plane_z)
                                                                                                                                                                                                                                                                                                                                    if l_teleport_dist >= 1000 then
                                                                                                                                                                                                                                                                                                                                        full_reset()
                                                                                                                                                                                                                                                                                                                                        logMsg(
                                                                                                                                                                                                                                                                                                                                        "FollowMe VER1.12 : teleport detected ("
                                                                                                                                                                                                                                                                                                                                        .. string.format("%.0f", l_teleport_dist)
                                                                                                                                                                                                                                                                                                                                        .. "m jump) - full_reset()"
                                                                                                                                                                                                                                                                                                                                        )
                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                prev_plane_x = fm_plane_x
                                                                                                                                                                                                                                                                                                                                prev_plane_z = fm_plane_z
                                                                                                                                                                                                                                                                                                                                if (
                                                                                                                                                                                                                                                                                                                                    fm_gear1_gnd = = 0 and fm_gear2_gnd == 0) and fm_new_flight > 1 then
                                                                                                                                                                                                                                                                                                                                    if
                                                                                                                                                                                                                                                                                                                                        flightstart = = 0 then
                                                                                                                                                                                                                                                                                                                                        flightstart = fm_run_time + 180
                                                                                                                                                                                                                                                                                                                                        if followme_wnd ~= nil then
                                                                                                                                                                                                                                                                                                                                            hide_window()
                                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                    if fm_run_time > flightstart and flightstart ~= 9999 then
                                                                                                                                                                                                                                                                                                                                        arrival_gate = 0
                                                                                                                                                                                                                                                                                                                                        flightstart = 9999
                                                                                                                                                                                                                                                                                                                                        ground_time = 0
                                                                                                                                                                                                                                                                                                                                        prepare_kill_objects = true
                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                if holder_wnd and
                                                                                                                                                                                                                                                                                                                                    toggle_window = = true then
                                                                                                                                                                                                                                                                                                                                    toggle_window = false
                                                                                                                                                                                                                                                                                                                                    if followme_wnd ~= nil then
                                                                                                                                                                                                                                                                                                                                        hide_window()
                                                                                                                                                                                                                                                                                                                                        else
                                                                                                                                                                                                                                                                                                                                            window_is_open = true
                                                                                                                                                                                                                                                                                                                                            show_window()
                                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                    local l_err = ""
                                                                                                                                                                                                                                                                                                                                    if
                                                                                                                                                                                                                                                                                                                                        FM_car_active = = true and #t_node > 0 and prev_taxi_light ~= fm_taxi_light and fm_taxi_light == 0 then
                                                                                                                                                                                                                                                                                                                                        if (
                                                                                                                                                                                                                                                                                                                                            depart_arrive = = 1 and curr_node >= #t_node) or (depart_arrive == 2 and curr_node == #t_node) then
                                                                                                                                                                                                                                                                                                                                            prepare_kill_objects = true
                                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                    if
                                                                                                                                                                                                                                                                                                                                        FM_car_active = = false and get_from_SimBrief == true and fm_gear1_gnd == 1 and holder_wnd then
                                                                                                                                                                                                                                                                                                                                        if
                                                                                                                                                                                                                                                                                                                                            (prev_taxi_light ~= fm_taxi_light and
                                                                                                                                                                                                                                                                                                                                            fm_taxi_light = = 1)
                                                                                                                                                                                                                                                                                                                                            or (prev_beacon_light ~= fm_beacon_light and
                                                                                                                                                                                                                                                                                                                                            fm_beacon_light = = 1)
                                                                                                                                                                                                                                                                                                                                            then
                                                                                                                                                                                                                                                                                                                                            get_airport_elements()
                                                                                                                                                                                                                                                                                                                                            if
                                                                                                                                                                                                                                                                                                                                                taxiway_network = = "" then
                                                                                                                                                                                                                                                                                                                                                if depart_runway ~= "" then
                                                                                                                                                                                                                                                                                                                                                    l_err = determine_XP_route()
                                                                                                                                                                                                                                                                                                                                                    if
                                                                                                                                                                                                                                                                                                                                                        l_err = = "" or (l_err ~= "" and tonumber(l_err) > 0) then
                                                                                                                                                                                                                                                                                                                                                        prepare_show_objects = true
                                                                                                                                                                                                                                                                                                                                                        else
                                                                                                                                                                                                                                                                                                                                                            update_msg(l_err)
                                                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                                    else
                                                                                                                                                                                                                                                                                                                                                        update_msg("-15")
                                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                            prev_taxi_light = fm_taxi_light
                                                                                                                                                                                                                                                                                                                                            prev_beacon_light = fm_beacon_light
                                                                                                                                                                                                                                                                                                                                            if
                                                                                                                                                                                                                                                                                                                                                speed_limiter
                                                                                                                                                                                                                                                                                                                                                and FM_car_active
                                                                                                                                                                                                                                                                                                                                                and
                                                                                                                                                                                                                                                                                                                                                fm_gear1_gnd = = 1
                                                                                                                                                                                                                                                                                                                                                and
                                                                                                                                                                                                                                                                                                                                                fm_gear2_gnd = = 1
                                                                                                                                                                                                                                                                                                                                                and fm_gnd_spd > 10.288
                                                                                                                                                                                                                                                                                                                                                and fm_run_time > speed_warn_time
                                                                                                                                                                                                                                                                                                                                                then
                                                                                                                                                                                                                                                                                                                                                play_sound(snd_keep_speed)
                                                                                                                                                                                                                                                                                                                                                speed_warn_time = fm_run_time + 15
                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                            if
                                                                                                                                                                                                                                                                                                                                                FM_car_active = = false
                                                                                                                                                                                                                                                                                                                                                and
                                                                                                                                                                                                                                                                                                                                                flightstart = = 9999
                                                                                                                                                                                                                                                                                                                                                and (
                                                                                                                                                                                                                                                                                                                                                fm_gear1_gnd = = 1 and fm_gear2_gnd == 1)
                                                                                                                                                                                                                                                                                                                                                and
                                                                                                                                                                                                                                                                                                                                                ground_time = = 0
                                                                                                                                                                                                                                                                                                                                                and
                                                                                                                                                                                                                                                                                                                                                fm_taxi_light = = 1
                                                                                                                                                                                                                                                                                                                                                and fm_gnd_spd < 15
                                                                                                                                                                                                                                                                                                                                                then
                                                                                                                                                                                                                                                                                                                                                get_airport_elements()
                                                                                                                                                                                                                                                                                                                                                if
                                                                                                                                                                                                                                                                                                                                                    taxiway_network = = "" then
                                                                                                                                                                                                                                                                                                                                                    if
                                                                                                                                                                                                                                                                                                                                                        random_gate = = true or arrival_gate > 0 then
                                                                                                                                                                                                                                                                                                                                                        if
                                                                                                                                                                                                                                                                                                                                                            arrival_gate = = 0 then
                                                                                                                                                                                                                                                                                                                                                            l_err = auto_assign_gate()
                                                                                                                                                                                                                                                                                                                                                            if
                                                                                                                                                                                                                                                                                                                                                                l_err = = "1" then
                                                                                                                                                                                                                                                                                                                                                                play_text = "No suitable gate for this aircraft. Randomly assigned to gate "
                                                                                                                                                                                                                                                                                                                                                                .. t_gate[arrival_gate].ID
                                                                                                                                                                                                                                                                                                                                                                elseif
                                                                                                                                                                                                                                                                                                                                                                    l_err = = "2" then
                                                                                                                                                                                                                                                                                                                                                                    play_text = "Assigned to " .. t_gate[arrival_gate].ID
                                                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                                                play_time = fm_run_time + 5
                                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                                            if
                                                                                                                                                                                                                                                                                                                                                                window_is_open = = false then
                                                                                                                                                                                                                                                                                                                                                                l_err = determine_XP_route()
                                                                                                                                                                                                                                                                                                                                                                if
                                                                                                                                                                                                                                                                                                                                                                    l_err = = "" or (l_err ~= "" and tonumber(l_err) > 0) then
                                                                                                                                                                                                                                                                                                                                                                    prepare_show_objects = true
                                                                                                                                                                                                                                                                                                                                                                    else
                                                                                                                                                                                                                                                                                                                                                                        update_msg(l_err)
                                                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                                            else
                                                                                                                                                                                                                                                                                                                                                                update_msg("-15")
                                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                                            ground_time = 1
                                                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                                                        if play_time ~= 0 then
                                                                                                                                                                                                                                                                                                                                                            if fm_run_time > play_time then
                                                                                                                                                                                                                                                                                                                                                                XPLMSpeakString(play_text)
                                                                                                                                                                                                                                                                                                                                                                play_text = ""
                                                                                                                                                                                                                                                                                                                                                                play_time = 0
                                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                                                        if
                                                                                                                                                                                                                                                                                                                                                            prepare_show_objects = = true then
                                                                                                                                                                                                                                                                                                                                                            FM_car_active = true
                                                                                                                                                                                                                                                                                                                                                            load_object()
                                                                                                                                                                                                                                                                                                                                                            load_path()
                                                                                                                                                                                                                                                                                                                                                            start_car()
                                                                                                                                                                                                                                                                                                                                                            rampstart_chg = true
                                                                                                                                                                                                                                                                                                                                                            prepare_show_objects = false
                                                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                                                        if
                                                                                                                                                                                                                                                                                                                                                            prepare_kill_objects = = true then
                                                                                                                                                                                                                                                                                                                                                            FM_car_active = false
                                                                                                                                                                                                                                                                                                                                                            unload_object()
                                                                                                                                                                                                                                                                                                                                                            unload_path()
                                                                                                                                                                                                                                                                                                                                                            if kill_is_manual then
                                                                                                                                                                                                                                                                                                                                                                unload_rampstart()
                                                                                                                                                                                                                                                                                                                                                                rampstart_chg = false
                                                                                                                                                                                                                                                                                                                                                                kill_is_manual = false
                                                                                                                                                                                                                                                                                                                                                                update_msg("7")
                                                                                                                                                                                                                                                                                                                                                                curr_ICAO = ""
                                                                                                                                                                                                                                                                                                                                                                local l_saved_runway = depart_runway
                                                                                                                                                                                                                                                                                                                                                                local l_saved_depart = depart_arrive
                                                                                                                                                                                                                                                                                                                                                                local l_saved_arrival_gate = arrival_gate
                                                                                                                                                                                                                                                                                                                                                                local l_saved_gatetext = gatetext
                                                                                                                                                                                                                                                                                                                                                                local l_saved_depart_gate = depart_gate
                                                                                                                                                                                                                                                                                                                                                                initialise_routes()
                                                                                                                                                                                                                                                                                                                                                                depart_runway = l_saved_runway
                                                                                                                                                                                                                                                                                                                                                                depart_arrive = l_saved_depart
                                                                                                                                                                                                                                                                                                                                                                arrival_gate = l_saved_arrival_gate
                                                                                                                                                                                                                                                                                                                                                                gatetext = l_saved_gatetext
                                                                                                                                                                                                                                                                                                                                                                depart_gate = l_saved_depart_gate
                                                                                                                                                                                                                                                                                                                                                                if show_rampstart and (arrival_gate > 0 or depart_gate > 0) then
                                                                                                                                                                                                                                                                                                                                                                    rampstart_chg = true
                                                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                                                else
                                                                                                                                                                                                                                                                                                                                                                    if
                                                                                                                                                                                                                                                                                                                                                                        flightstart = = 9999 then
                                                                                                                                                                                                                                                                                                                                                                        unload_rampstart()
                                                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                                                    initialise_routes()
                                                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                                                prepare_kill_objects = false
                                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                                            if not holder_wnd and fm_new_flight > 1 then
                                                                                                                                                                                                                                                                                                                                                                screen_width = SCREEN_WIDTH
                                                                                                                                                                                                                                                                                                                                                                show_holder()
                                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                                            if holder_wnd and screen_width ~= SCREEN_WIDTH then
                                                                                                                                                                                                                                                                                                                                                                screen_width = SCREEN_WIDTH
                                                                                                                                                                                                                                                                                                                                                                float_wnd_set_position(holder_wnd, screen_width - Holder_len, Win_Y)
                                                                                                                                                                                                                                                                                                                                                                if followme_wnd ~= nil then
                                                                                                                                                                                                                                                                                                                                                                    float_wnd_set_position(followme_wnd, screen_width - 430, Win_Y)
                                                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                                            if holder_wnd then
                                                                                                                                                                                                                                                                                                                                                                if
                                                                                                                                                                                                                                                                                                                                                                    MOUSE_X >= SCREEN_WIDTH - Holder_len
                                                                                                                                                                                                                                                                                                                                                                    and MOUSE_X <= SCREEN_WIDTH
                                                                                                                                                                                                                                                                                                                                                                    and MOUSE_Y >= SCREEN_HIGHT - (Win_Y + Holder_len)
                                                                                                                                                                                                                                                                                                                                                                    and MOUSE_Y <= SCREEN_HIGHT - Win_Y
                                                                                                                                                                                                                                                                                                                                                                    then
                                                                                                                                                                                                                                                                                                                                                                    float_wnd_bring_to_front(holder_wnd)
                                                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                                                if
                                                                                                                                                                                                                                                                                                                                                                    holder_drag = = 3 and followme_wnd ~= nil then
                                                                                                                                                                                                                                                                                                                                                                    float_wnd_set_position(followme_wnd, screen_width - 430, Win_Y)
                                                                                                                                                                                                                                                                                                                                                                    holder_drag = 2
                                                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                                            if followme_wnd ~= nil then
                                                                                                                                                                                                                                                                                                                                                                local l_over_holder = (
                                                                                                                                                                                                                                                                                                                                                                MOUSE_X >= SCREEN_WIDTH - Holder_len
                                                                                                                                                                                                                                                                                                                                                                and MOUSE_X <= SCREEN_WIDTH
                                                                                                                                                                                                                                                                                                                                                                and MOUSE_Y >= SCREEN_HIGHT - (Win_Y + Holder_len)
                                                                                                                                                                                                                                                                                                                                                                and MOUSE_Y <= SCREEN_HIGHT - Win_Y
                                                                                                                                                                                                                                                                                                                                                                )
                                                                                                                                                                                                                                                                                                                                                                if not l_over_holder then
                                                                                                                                                                                                                                                                                                                                                                    if
                                                                                                                                                                                                                                                                                                                                                                        MOUSE_X >= SCREEN_WIDTH - 400 - Holder_len
                                                                                                                                                                                                                                                                                                                                                                        and MOUSE_X <= SCREEN_WIDTH - Holder_len
                                                                                                                                                                                                                                                                                                                                                                        and MOUSE_Y >= SCREEN_HIGHT - (Win_Y + 400)
                                                                                                                                                                                                                                                                                                                                                                        and MOUSE_Y <= SCREEN_HIGHT - Win_Y
                                                                                                                                                                                                                                                                                                                                                                        then
                                                                                                                                                                                                                                                                                                                                                                        float_wnd_bring_to_front(followme_wnd)
                                                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                                                        function show_holder()
                                                                                                                                                                                                                                                                                                                                                            if
                                                                                                                                                                                                                                                                                                                                                                init_load = = 0 then
                                                                                                                                                                                                                                                                                                                                                                load_config()
                                                                                                                                                                                                                                                                                                                                                                init_load = 1
                                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                                            holder_wnd = float_wnd_create(Holder_len, Holder_len, 2, true)
                                                                                                                                                                                                                                                                                                                                                            float_wnd_set_position(holder_wnd, screen_width - Holder_len, Win_Y)
                                                                                                                                                                                                                                                                                                                                                            float_wnd_set_imgui_builder(holder_wnd, "build_holder")
                                                                                                                                                                                                                                                                                                                                                            float_wnd_set_onclose(holder_wnd, "closed_holder")
                                                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                                                        function hide_holder()
                                                                                                                                                                                                                                                                                                                                                            if holder_wnd then
                                                                                                                                                                                                                                                                                                                                                                float_wnd_destroy(holder_wnd)
                                                                                                                                                                                                                                                                                                                                                                holder_wnd = nil
                                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                                                        function show_window()
                                                                                                                                                                                                                                                                                                                                                            window_first_access = true
                                                                                                                                                                                                                                                                                                                                                            followme_wnd = float_wnd_create(400, 525, 2, true)
                                                                                                                                                                                                                                                                                                                                                            float_wnd_set_position(followme_wnd, screen_width - 400 - Holder_len, Win_Y)
                                                                                                                                                                                                                                                                                                                                                            float_wnd_set_imgui_builder(followme_wnd, "build_window")
                                                                                                                                                                                                                                                                                                                                                            float_wnd_set_onclose(followme_wnd, "closed_window")
                                                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                                                        function hide_window()
                                                                                                                                                                                                                                                                                                                                                            if followme_wnd ~= nil then
                                                                                                                                                                                                                                                                                                                                                                float_wnd_destroy(followme_wnd)
                                                                                                                                                                                                                                                                                                                                                                followme_wnd = nil
                                                                                                                                                                                                                                                                                                                                                                window_is_open = false
                                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                                        end
                                                                                                                                                                                                                                                                                                                                                        function build_window(wnd, x, y)
                                                                                                                                                                                                                                                                                                                                                            local l_err = ""
