                                                                                                                                                                                                                                                                                                                                                                            end
                                                                                                                                                                                                                                                                                                                                                                            imgui.PopStyleColor()
                                                                                                                                                                                                                                                                                                                                                                            imgui.SetCursorPosY(48)
                                                                                                                                                                                                                                                                                                                                                                            imgui.SetCursorPosX(10)
                                                                                                                                                                                                                                                                                                                                                                            imgui.SetWindowFontScale(1.2)
                                                                                                                                                                                                                                                                                                                                                                            if get_from_SimBrief and
                                                                                                                                                                                                                                                                                                                                                                                sb_fetch_status = = "OK" and sb_dest_icao ~= "" then
