                                                                                                                                                                                                                                                                                                                                                                                imgui.SetCursorPosX(18)
                                                                                                                                                                                                                                                                                                                                                                                if imgui.RadioButton(" Departure : ", depart_arrive = = 1, false) then
                                                                                                                                                                                                                                                                                                                                                                                    depart_arrive = 1
                                                                                                                                                                                                                                                                                                                                                                                    flightstart = 0
                                                                                                                                                                                                                                                                                                                                                                                    rampstart_chg = true
