                                                                                                                                                                                                                                                                                                                                                                                        apply_simbrief_runway()
                                                                                                                                                                                                                                                                                                                                                                                    end
                                                                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                                                                if depart_gate > 0 then
                                                                                                                                                                                                                                                                                                                                                                                    imgui.SameLine()
                                                                                                                                                                                                                                                                                                                                                                                    imgui.SetCursorPosX(134)
                                                                                                                                                                                                                                                                                                                                                                                    imgui.TextUnformatted(t_gate[depart_gate].ID)
                                                                                                                                                                                                                                                                                                                                                                                end
                                                                                                                                                                                                                                                                                                                                                                                imgui.SetCursorPosY(l_y + 25)
                                                                                                                                                                                                                                                                                                                                                                                imgui.SetCursorPosX(48)
                                                                                                                                                                                                                                                                                                                                                                                imgui.TextUnformatted("To Runway : ")
